// ============================================================
// src/lib/fonts/bild.ts
// ============================================================
// Font BILD Condensed Black (Lineto) — embarquée en base64 pour usage
// dans tous les rendus PDF/HTML de l'app Meshuga.
//
// Format : OpenType (.otf), 50 KB → ~65 KB encodés en base64.
// Licence : Lineto, propriété SAS AEGIA FOOD.
// Charte : titres / infos principales (cf. charte graphique V5).
//
// ⚠️ ATTENTION : ce fichier contient un blob base64 de ~65 KB.
// Ne JAMAIS éditer via le GitHub web editor (risque de troncature
// silencieuse → build Vercel cassé). Pour mettre à jour, remplacer
// le fichier .otf source et régénérer le base64 via le script
// d'intégration Python (scripts/encode-font.py).
//
// Usage : ne PAS importer directement, utiliser plutôt
//   import { BILD_CONDENSED_FONTFACE } from "@/lib/fonts"
// ============================================================

export const BILD_CONDENSED_BLACK_OTF_B64 = ""

// Helper : déclaration @font-face prête à injecter dans une balise <style>
export const BILD_CONDENSED_FONTFACE =
  "@font-face { font-family: 'BILD Condensed'; font-weight: 900; font-style: normal; " +
  "src: url(data:font/otf;base64," + BILD_CONDENSED_BLACK_OTF_B64 + ") format('opentype'); " +
  "font-display: block; }"

// Stack CSS prêt à l'emploi (utilisable côté client immédiatement)
export const BILD_CONDENSED_STACK = "'BILD Condensed', 'Arial Narrow', Arial Black, sans-serif"
